#define LDW_LIST_MORE 1

enum ldw_ctl_requests {
  LDW_CTL_NEXT = 0, LDW_CTL_PREV, LDW_CTL_EDIT, LDW_CTL_INSERT_AFTER, 
  LDW_CTL_INSERT_BEFORE, LDW_CTL_DELETE, LDW_CTL_GET
};

struct ldw_rule {
  uint32_t size;
  uid_t tgtUser;
  gid_t tgtGroup;
  int filt_mode;
