static ssize_t ldw_default_write(struct file *f, const char __user *buff, size_t s,
    loff_t * off)
{
  char c;
  if (!*off) {
    if (copy_from_user(&c, buff, 1))
      return -EFAULT;
    if (c == '0')
      default_action = 0;
    else if (c == '1')
      default_action = 1;
    else
      return -EINVAL;
  }

  // Ignore any additional writes.
  return s;
}

