#define LDW_RULE_FILT_USER   0x08
#define LDW_RULE_FILT_GROUP  0x10
#define LDW_RULE_FILT_PERMIT 0x20

#define LDW_RULE_FILT_MASK 0x3f

#define LDW_RES_NOMATCH -1
#define LDW_RES_DENY    0
