static inline void __put_rule(struct ldw_rule *obj) {
  if (unlikely(obj->magic != LDW_MAGIC)) {
    printk("Not a ldw_rule!\n");
    BUG();
  }
  if (refcount_dec_and_test(&obj->refs)) {
    obj->magic = LDW_MAGIC_DEAD;
    kfree(obj);
