#define msg(m,...) fprintf(stderr, m "\n", ##__VA_ARGS__)
#define LERR(m, ...) do {                             \
  msg("ERROR (line %d): " m, linenum, ##__VA_ARGS__); \
  errors++;                                           \
} while (0)
#define LWARN(m, ...) do {                              \
