        out->filt_mode ^= LDW_RULE_FILT_PERMIT;
        if (out->filt_mode & LDW_RULE_FILT_PERMIT)
          puts("This is now a permit rule.");
        else 
          puts("This is now a deny rule.");
        break;
      case 4: // done
        print_rule(out);
        fputs("Do you want to continue? (y/n) ", stdout);
        while ((c = getchar()) != EOF) {
          if (c != '\n')
            end_line();
          c = tolower(c);
          if (c == 'y')
            return 1;
          else if (c == 'n')
            goto loop;

          fputs("(y/n) ", stdout);
