  } else {
    obj = kmalloc(sizeof(struct ldw_rule), GFP_KERNEL);
    if (obj) {
      obj->refs = (refcount_t)REFCOUNT_INIT(1);
      obj->name = NULL;
      obj->magic = LDW_MAGIC;
      obj->name_len = 0;
    } else
      return ERR_PTR(-ENOMEM);
  }

  return obj;
}

